<template>
  <div class="policy-list">
    <el-card>
      <div slot="header" style="display: flex; justify-content: space-between; align-items: center">
        <span>IT政策管理</span>
        <el-button type="primary" size="small" icon="el-icon-upload2" @click="uploadVisible = true">上传政策</el-button>
      </div>
      <el-table :data="policies" border stripe>
        <el-table-column prop="title" label="标题" />
        <el-table-column prop="description" label="描述" show-overflow-tooltip />
        <el-table-column prop="file_name" label="文件名" />
        <el-table-column label="文件大小" width="120">
          <template slot-scope="scope">{{ formatSize(scope.row.file_size) }}</template>
        </el-table-column>
        <el-table-column label="上传时间" width="180">
          <template slot-scope="scope">{{ formatDate(scope.row.created_at) }}</template>
        </el-table-column>
        <el-table-column label="操作" width="280">
          <template slot-scope="scope">
            <el-button size="mini" @click="handlePreview(scope.row)">预览</el-button>
            <el-button size="mini" @click="handleEdit(scope.row)">编辑</el-button>
            <el-button size="mini" type="danger" @click="handleDelete(scope.row)">删除</el-button>
          </template>
        </el-table-column>
      </el-table>
    </el-card>

    <!-- 上传弹窗 -->
    <el-dialog title="上传政策文件" :visible.sync="uploadVisible" width="500px">
      <el-form :model="uploadForm" :rules="uploadRules" ref="uploadFormRef" label-width="80px">
        <el-form-item label="标题" prop="title">
          <el-input v-model="uploadForm.title" placeholder="请输入政策标题" />
        </el-form-item>
        <el-form-item label="描述">
          <el-input v-model="uploadForm.description" type="textarea" :rows="2" placeholder="请输入描述" />
        </el-form-item>
        <el-form-item label="文件" prop="file">
          <el-upload
            ref="uploader"
            :auto-upload="false"
            :limit="1"
            :on-change="handleFileChange"
            :on-remove="handleFileRemove"
            :file-list="fileList"
            drag
          >
            <i class="el-icon-upload"></i>
            <div class="el-upload__text">将文件拖到此处，或<em>点击上传</em></div>
            <div class="el-upload__tip" slot="tip">支持 PDF、DOC、DOCX、XLS、XLSX 等格式</div>
          </el-upload>
        </el-form-item>
      </el-form>
      <span slot="footer">
        <el-button @click="uploadVisible = false">取消</el-button>
        <el-button type="primary" :loading="uploading" @click="handleUpload">上传</el-button>
      </span>
    </el-dialog>

    <!-- 编辑弹窗 -->
    <el-dialog title="编辑政策" :visible.sync="editVisible" width="500px">
      <el-form :model="editForm" label-width="80px">
        <el-form-item label="标题">
          <el-input v-model="editForm.title" />
        </el-form-item>
        <el-form-item label="描述">
          <el-input v-model="editForm.description" type="textarea" :rows="2" />
        </el-form-item>
      </el-form>
      <span slot="footer">
        <el-button @click="editVisible = false">取消</el-button>
        <el-button type="primary" @click="handleEditSubmit">保存</el-button>
      </span>
    </el-dialog>

    <!-- 预览弹窗 -->
    <el-dialog title="文件预览" :visible.sync="previewVisible" width="80%" top="5vh">
      <div v-if="previewType === 'pdf'" style="height: 70vh">
        <iframe :src="previewUrl" style="width: 100%; height: 100%; border: none"></iframe>
      </div>
      <div v-else-if="previewType === 'image'" style="text-align: center">
        <img :src="previewUrl" style="max-width: 100%; max-height: 70vh" />
      </div>
      <div v-else style="text-align: center; padding: 40px">
        <p>该文件格式不支持在线预览</p>
        <el-button type="primary" @click="downloadFile">下载文件</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import { getPolicies, createPolicy, updatePolicy, deletePolicy, getPolicyPreviewUrl } from '@/api/policy'

export default {
  name: 'PolicyList',
  data() {
    return {
      policies: [],
      uploadVisible: false,
      uploading: false,
      uploadForm: { title: '', description: '' },
      uploadRules: {
        title: [{ required: true, message: '请输入标题', trigger: 'blur' }]
      },
      fileList: [],
      selectedFile: null,
      editVisible: false,
      editForm: { id: null, title: '', description: '' },
      previewVisible: false,
      previewUrl: '',
      previewType: ''
    }
  },
  mounted() {
    this.fetchData()
  },
  methods: {
    async fetchData() {
      try {
        const res = await getPolicies()
        this.policies = res.data || []
      } catch (e) {
        console.error(e)
      }
    },
    handleFileChange(file) {
      this.selectedFile = file.raw
      this.fileList = [file]
    },
    handleFileRemove() {
      this.selectedFile = null
      this.fileList = []
    },
    async handleUpload() {
      this.$refs.uploadFormRef.validate(async valid => {
        if (!valid) return
        if (!this.selectedFile) {
          this.$message.warning('请选择文件')
          return
        }
        this.uploading = true
        try {
          const formData = new FormData()
          formData.append('title', this.uploadForm.title)
          formData.append('description', this.uploadForm.description)
          formData.append('file', this.selectedFile)
          await createPolicy(formData)
          this.$message.success('上传成功')
          this.uploadVisible = false
          this.uploadForm = { title: '', description: '' }
          this.selectedFile = null
          this.fileList = []
          this.fetchData()
        } catch (e) {
          console.error(e)
        } finally {
          this.uploading = false
        }
      })
    },
    handleEdit(row) {
      this.editForm = { id: row.id, title: row.title, description: row.description }
      this.editVisible = true
    },
    async handleEditSubmit() {
      try {
        await updatePolicy(this.editForm.id, {
          title: this.editForm.title,
          description: this.editForm.description
        })
        this.$message.success('更新成功')
        this.editVisible = false
        this.fetchData()
      } catch (e) {
        console.error(e)
      }
    },
    handleDelete(row) {
      this.$confirm('确定要删除该政策吗？', '提示', { type: 'warning' }).then(async () => {
        try {
          await deletePolicy(row.id)
          this.$message.success('删除成功')
          this.fetchData()
        } catch (e) {
          console.error(e)
        }
      }).catch(() => {})
    },
    handlePreview(row) {
      const url = getPolicyPreviewUrl(row.id)
      const fileType = row.file_type || ''
      if (fileType.includes('pdf')) {
        this.previewType = 'pdf'
      } else if (fileType.startsWith('image/')) {
        this.previewType = 'image'
      } else {
        this.previewType = 'other'
      }
      this.previewUrl = url
      this.previewVisible = true
    },
    downloadFile() {
      window.open(this.previewUrl, '_blank')
    },
    formatSize(size) {
      if (!size) return '-'
      if (size < 1024) return size + ' B'
      if (size < 1024 * 1024) return (size / 1024).toFixed(1) + ' KB'
      return (size / (1024 * 1024)).toFixed(1) + ' MB'
    },
    formatDate(dateStr) {
      if (!dateStr) return '-'
      return new Date(dateStr).toLocaleString('zh-CN')
    }
  }
}
</script>
